let trigger = {};
try {
  trigger = $('Verificar Duplicata').first().json || {};
} catch (e) {}

let sessaoData = null;
let caixaSessao = null;
try {
  sessaoData = $('Buscar Sessão Ativa').first().json || null;
  if (sessaoData && sessaoData.caixa_codigo) {
    caixaSessao = sessaoData.caixa_codigo;
  }
  if (sessaoData && sessaoData.problema_pendente && typeof sessaoData.problema_pendente === 'string') {
    try {
      sessaoData.problema_pendente = JSON.parse(sessaoData.problema_pendente);
    } catch (e) {
      sessaoData.problema_pendente = null;
    }
  }
} catch (e) {}

// Fallback para caixa do buttonId
if (!caixaSessao && trigger.buttonId) {
  const caixaMatch = trigger.buttonId.match(/[_](C\d+)/i);
  if (caixaMatch) {
    caixaSessao = caixaMatch[1].toUpperCase();
  }
}

let usuario = {};
try {
  usuario = $('Buscar Usuário').first().json || {};
} catch (e) {}


