};


// ╔═══════════════════════════════════════════════════════════════╗
// ║ [SHARED] EXTRAÇÃO DE DADOS BÁSICOS                           ║
// ╚═══════════════════════════════════════════════════════════════╝

let telefone = trigger.telefone || usuario.telefone || '';
if (telefone) telefone = telefone.toString().replace(/\D/g, '');

const content = (trigger.content || '').trim();
const textoLimpo = content.replace(/['"\\]/g, '').trim();
const buttonId = trigger.buttonId || null;
const mediaId = trigger.mediaId || trigger.imageUrl || null;
const mediaType = trigger.tipoInteracao === 'imagem' ? 'image' : null;

// Localização — múltiplas fontes
let latitude = null;
let longitude = null;

if (trigger.latitude && trigger.longitude) {
  latitude = parseFloat(trigger.latitude);
  longitude = parseFloat(trigger.longitude);
} 
else if (trigger.message?.latitude && trigger.message?.longitude) {
  latitude = parseFloat(trigger.message.latitude);
  longitude = parseFloat(trigger.message.longitude);
}
else if (trigger.location?.latitude && trigger.location?.longitude) {
  latitude = parseFloat(trigger.location.latitude);
  longitude = parseFloat(trigger.location.longitude);
}
else if (trigger.message?.location?.latitude && trigger.message?.location?.longitude) {
  latitude = parseFloat(trigger.message.location.latitude);
  longitude = parseFloat(trigger.message.location.longitude);
}
else if (content && content.includes('maps.google.com')) {
  const coordMatch = content.match(/[?&]q=(-?\d+\.?\d*)[%2C,]+(-?\d+\.?\d*)/i);
  if (coordMatch) {
    latitude = parseFloat(coordMatch[1]);
    longitude = parseFloat(coordMatch[2]);
  }
}
else if (content && content.includes('google.com/maps')) {
  const coordMatch = content.match(/@(-?\d+\.?\d*),(-?\d+\.?\d*)/);
  if (coordMatch) {
    latitude = parseFloat(coordMatch[1]);
    longitude = parseFloat(coordMatch[2]);
  }
}

const temLocalizacao = latitude !== null && longitude !== null && !isNaN(latitude) && !isNaN(longitude);


