// ║ [ROUTER] DESPACHO PRINCIPAL                                   ║
// ╚═══════════════════════════════════════════════════════════════╝

if (buttonId) {
  tipoInput = 'botao';
  dadosExtraidos.buttonId = buttonId;

  // 1. Rota exata
  if (ROTAS_BUTTON[buttonId]) {
    ROTAS_BUTTON[buttonId]();
  }
  // 2. Rota regex
  else {
    const rota = ROTAS_REGEX.find(r => buttonId.match(r.pattern));
    if (rota) {
      rota.handler(buttonId);
    } else {
      // Botão não mapeado
      tipoInput = 'botao_desconhecido';
      respostaJSON = {
        mensagem: `⚠️ Botão não reconhecido.\n\nSelecione uma opção:`,
        botoes: [
          { id: "modulo_eeg", title: "🧠 Módulo EEG" },
          { id: "menu_principal", title: "🏠 Menu" }
        ]
      };
    }
  }
}
// 3. Localização recebida
else if (temLocalizacao) {
  handleLocalizacao();
}
// 4. Seleção de modems (input numérico com contexto)
else if (!buttonId && content && /^[\d,\s]+$/.test(content) && 
         sessaoData?.problema_pendente?.aguardando === 'modems') {
  handleSelecaoModems();
}
// 5. QR Code
else if (qrMatch) {
  handleQRCode(qrMatch);
}
// 6. Código de item (C8-03-001)
else if (content.match(/^C\d+-\d{2}-\d{3}$/i)) {
  handleCodigoItem();
}
// 7. Comando de troca "C8 3"
else if (content.match(/^C\d+\s+\d+$/i)) {
  handleComandoTroca();
}
// 8. Saudações e comandos comuns (PRIORIDADE sobre contexto)
else if (/^(ola|olá|oi|hi|hello|hey|bom dia|boa tarde|boa noite|menu|inicio|começar|ajuda|help)$/i.test(content)) {
  handleSaudacao();
}
// 9. Texto com contexto de sessão ativo
else if (!buttonId && content && sessaoData?.problema_pendente) {
  handleTextoContexto();
}
// 10. Possível descrição de problema (5-200 chars, sem botão)
else if (!buttonId && content.length >= 5 && content.length <= 200) {
  handlePossivelDescricao();
}
// 11. Fallback
else {
  handleTextoNaoReconhecido();
}


