function handlePlantaoMotivoItens(buttonId) {
  const match = buttonId.match(/^motivo_([a-z_]+)_(C\d+)$/i);
  const motivo = match[1];
  const caixa = match[2].toUpperCase();

  dadosExtraidos.caixa = caixa;
  dadosExtraidos.motivo = motivo;

  if (motivo === 'outro') {
    // Se motivo é "outro", pedir descrição primeiro
    executarSQLAntes = true;
    sqlAcaoAntes = 'preparar_motivo_outro';
    sqlQueryAntes = `
      UPDATE eeg_sessao_retirada 
      SET problema_pendente = jsonb_build_object(
        'tipo_sessao', 'finalizar_plantao_outro',
        'caixa', '${caixa}',
        'motivo', 'outro'
      ),
      atualizada_em = NOW(),
      expira_em = NOW() + INTERVAL '30 minutes'
      WHERE telefone LIKE '%' || RIGHT('${telefone}', 11) || '%'
        AND status NOT IN ('finalizada', 'cancelada', 'expirada')
    `;

    respostaJSON = {
      mensagem: `📝 *OUTRO MOTIVO*\n\n📦 Caixa: *${caixa}*\n\nDescreva o motivo para manter os itens:`,
      botoes: [
        { id: `plantao_manter_itens_${caixa}`, title: "🔙 Voltar" },
        { id: "modulo_eeg", title: "🔙 Menu EEG" }
      ],
      _aguardandoMotivoOutro: true
    };
  } else {
    // Motivo pré-definido - pedir localização via BOTÃO
    executarSQLAntes = true;
    sqlAcaoAntes = 'preparar_finalizar_plantao_loc';
    sqlQueryAntes = `
      WITH cancela AS (
        UPDATE eeg_sessao_retirada
        SET status = 'cancelada', atualizada_em = NOW()
        WHERE telefone LIKE '%' || RIGHT('${telefone}', 11) || '%'
          AND status NOT IN ('finalizada', 'cancelada', 'expirada')
        RETURNING id
      )
      INSERT INTO eeg_sessao_retirada (
        telefone, usuario_id, caixa_codigo, status, problema_pendente,
        expira_em, iniciada_em, atualizada_em
      ) VALUES (
        '${telefone}', ${userId}, '${caixa}', 'aguardando_localizacao',
        '{"tipo_sessao": "finalizar_plantao", "caixa": "${caixa}", "motivo": "${motivo}"}'::JSONB,
        NOW() + INTERVAL '30 minutes', NOW(), NOW()
      )
      RETURNING id
    `;

    const motivoLabel = MOTIVOS_MANTER_ITENS[motivo] || motivo;

    respostaJSON = {
      mensagem: "📍 Solicitando localização...",
      botoes: [
        { id: `plantao_manter_itens_${caixa}`, title: "🔙 Voltar" },
        { id: "modulo_eeg", title: "🔙 Menu EEG" }
      ],
      enviar_botao_localizacao: true,
      tipo_localizacao: 'plantao_finalizar',
      mensagem_botao_localizacao: `📍 *CONFIRMAÇÃO DE LOCALIZAÇÃO*

🔴 *Finalizar Plantão*
📦 Caixa: *${caixa}*
📝 Motivo: ${motivoLabel}

Para finalizar o plantão mantendo os itens, precisamos registrar sua localização.

⚠️ Clique no botão abaixo para compartilhar sua localização via GPS.

⏱️ Você tem *5 minutos* para responder.`
    };
  }
}


