// Substituir o placeholder handleTextoSelecaoEmprestimo()
function handleTextoSelecaoEmprestimo() {
  // Dispatcher - verifica qual tipo de input é

  // 1. Número de item (1-13)
  if (content.match(/^\d+$/) && parseInt(content) >= 1 && parseInt(content) <= 13) {
    handleTextoNumeroItemEmprestimo();
    return;
  }

  // 2. Código de caixa (C2 ou EEG-C02-XXXXX)
  if (content.match(/^C\d+$/i) || content.match(/^EEG-C(\d+)-[A-Z0-9]{8}$/i)) {
    handleTextoCodigoCaixaEmprestimo();
    return;
  }

  // Não reconhecido
  respostaJSON = {
    mensagem: "🤔 Não entendi. Digite:\n• Número do item (1-13)\n• Código de caixa (ex: C5)",
    botoes: [
      { id: "eeg_emprestimo", title: "🔙 Voltar" },
      { id: "modulo_eeg", title: "🔙 Menu EEG" }
    ]
  };
}

function handleTextoNumeroItemEmprestimo() {
  tipoInput = 'numero_item_emprestimo';
  const itemNum = parseInt(content);
  const itemNome = getItemNome(itemNum);
  const caixaOrigem = sessaoData?.problema_pendente?.caixa_origem;
  const caixaDestino = sessaoData?.problema_pendente?.caixa_destino;

  dadosExtraidos.caixaOrigem = caixaOrigem;
  dadosExtraidos.caixaDestino = caixaDestino;
  dadosExtraidos.itemEmprestimo = itemNum;

  executarSQLAntes = true;
  sqlAcaoAntes = 'verificar_item_emprestimo';
  sqlQueryAntes = `
    SELECT 
      i.id as item_id,
      i.codigo as item_codigo,
      i.status as item_status,
      ip.nome as item_nome,
      '${caixaOrigem}' as caixa_origem,
      '${caixaDestino}' as caixa_destino,
      ${itemNum} as tipo_item,
      CASE WHEN i.status = 'ativo' THEN true ELSE false END as disponivel
    FROM eeg_itens i
    JOIN eeg_itens_padrao ip ON ip.numero = i.tipo_item
    WHERE i.caixa_codigo = '${caixaOrigem}'
      AND i.tipo_item = ${itemNum}
    LIMIT 1
  `;

  respostaJSON = {
    mensagem: `📦 *CONFIRMAR EMPRÉSTIMO*\n\n📤 De: *${caixaOrigem}*\n📥 Para: *${caixaDestino}* (sua caixa)\n\n🔧 Item: *${itemNum}. ${itemNome}*\n\n⚠️ *Confirma o empréstimo deste item?*`,
    botoes: [
      { id: `confirmar_emprestimo_${caixaOrigem}_${itemNum}_${caixaDestino}`, title: "✅ Confirmar" },
      { id: `emprestimo_caixa_${caixaOrigem}`, title: "🔙 Voltar" },
      { id: "modulo_eeg", title: "🔙 Menu EEG" }
    ],
    _verificarItemEmprestimo: true
  };
}

function handleTextoCodigoCaixaEmprestimo() {
  let caixaOrigem = '';
  if (content.match(/^C\d+$/i)) {
    caixaOrigem = content.toUpperCase();
  } else {
    const qr = content.match(/^EEG-C(\d+)-[A-Z0-9]{8}$/i);
    caixaOrigem = 'C' + parseInt(qr[1]);
  }

  const caixaDestino = sessaoData?.problema_pendente?.caixa_destino || sessaoData?.caixa_codigo;

  tipoInput = 'codigo_caixa_emprestimo';
  dadosExtraidos.caixaOrigem = caixaOrigem;
  dadosExtraidos.caixaDestino = caixaDestino;

  // Não pode pegar da própria caixa
  if (caixaOrigem.toUpperCase() === caixaDestino?.toUpperCase()) {
    respostaJSON = {
      mensagem: `⚠️ *Caixa Inválida*\n\nVocê não pode pegar item emprestado da sua própria caixa (${caixaOrigem}).\n\nDigite outro código de caixa.`,
      botoes: [
        { id: "eeg_emprestimo", title: "🔙 Voltar" },
        { id: "modulo_eeg", title: "🔙 Menu EEG" }
      ]
    };
  } else {
    executarSQLAntes = true;
    sqlAcaoAntes = 'listar_itens_emprestimo_caixa';
    sqlQueryAntes = `
      WITH sessao AS (
        UPDATE eeg_sessao_retirada 
        SET problema_pendente = problema_pendente || 
              jsonb_build_object('caixa_origem', '${caixaOrigem}'),
            status = 'selecionando_item_emprestimo',
            atualizada_em = NOW(),
            expira_em = NOW() + INTERVAL '30 minutes'
        WHERE telefone LIKE '%' || RIGHT('${telefone}', 11) || '%'
          AND status NOT IN ('finalizada', 'cancelada', 'expirada')
        RETURNING id
      ),
      itens AS (
        SELECT * FROM buscar_itens_caixa_para_emprestimo('${caixaOrigem}')
      )
      SELECT 
        i.lista_itens_texto,
        i.lista_itens_json,
        '${caixaOrigem}' as caixa_origem,
        '${caixaDestino}' as caixa_destino,
        CASE WHEN (SELECT id FROM sessao) IS NOT NULL THEN true ELSE false END as sessao_atualizada
      FROM itens i
    `;

    respostaJSON = {
      mensagem: `📦 *Carregando itens de ${caixaOrigem}...*`,
      _preencherItensEmprestimoV15: true,
      _caixaOrigem: caixaOrigem,
      _caixaDestino: caixaDestino
    };
  }
}

