    respostaJSON = {
      mensagem: "⚠️ *Sem Permissão*\n\nApenas supervisores podem gerenciar bloqueios.",
      botoes: [{ id: "modulo_eeg", title: "🔙 Menu EEG" }]
    };
    return;
  }

  executarSQLAntes = true;
  sqlAcaoAntes = 'listar_caixas_para_bloqueio';
  sqlQueryAntes = `
    SELECT 
      codigo,
      status,
      COALESCE(bloqueada, false) as bloqueada,
      bloqueada_motivo,
      COALESCE(u.nome, '-') as tecnico_nome
    FROM eeg_caixas c
    LEFT JOIN hub_usuarios u ON u.id = c.tecnico_atual_id
    ORDER BY 
      CASE WHEN codigo ~ '^C[0-9]+$' 
           THEN LPAD(SUBSTRING(codigo FROM 2), 3, '0') 
           ELSE codigo 
      END
  `;

  respostaJSON = {
    mensagem: "🔒 *GERENCIAR BLOQUEIO*\n\nCarregando...",
    botoes: [{ id: "eeg_manutencao_menu", title: "🔙 Voltar" }],
