function handleExameMeus() {
  executarSQLAntes = true;
  sqlAcaoAntes = 'listar_meus_exames_plantao';
  sqlQueryAntes = `
    WITH plantao_atual AS (
      SELECT id, inicio_em
      FROM eeg_plantoes
      WHERE tecnico_id = ${userId}
        AND status = 'ativo'
      ORDER BY id DESC
      LIMIT 1
    )
    SELECT 
      e.id as exame_id,
      e.status,
      e.paciente_nome,
      e.hospital_nome,
      e.setor_leito,
      e.tipo_exame_nome,
      e.is_continuo,
      e.caixa_codigo,
      e.modem_codigo,
      e.itens_com_paciente,
      e.plantao_id,
      TO_CHAR(e.inicio_em, 'YYYY-MM-DD') as plantao_data,
      TO_CHAR(e.inicio_em, 'HH24:MI') as hora_inicio,
      TO_CHAR(e.fim_em, 'HH24:MI') as hora_fim,
      EXTRACT(EPOCH FROM (COALESCE(e.fim_em, NOW()) - e.inicio_em)) / 60 as duracao_minutos
    FROM eeg_exames e
    WHERE e.tecnico_id = ${userId}
      AND (
        e.status IN ('em_andamento', 'devolucao_parcial')
        OR (e.status = 'finalizado' AND e.plantao_id = (SELECT id FROM plantao_atual))
      )
    ORDER BY 
      CASE e.status 
        WHEN 'em_andamento' THEN 1 
        WHEN 'devolucao_parcial' THEN 2 
        ELSE 3 
      END,
      e.inicio_em DESC
  `;

  respostaJSON = {
    mensagem: "📊 *Carregando seus exames...*",
    _preencherMeusExamesV16: true
  };
}

function handleExameMeusV14() {
  // Alias para compatibilidade v14
  executarSQLAntes = true;
  sqlAcaoAntes = 'listar_meus_exames';
  sqlQueryAntes = `
    SELECT 
      c.codigo,
      c.status as caixa_status,
      m.created_at as retirada_em,
      s.modem_selecionado,
      s.itens_selecionados,
      ec.id as exame_continuo_id,
      ec.status as exame_status,
      ec.hospital,
      ec.leito,
      CASE 
        WHEN ec.id IS NOT NULL THEN 'continuo'
        ELSE 'normal'
      END as tipo_exame,
      TO_CHAR(m.created_at, 'DD/MM HH24:MI') as retirada_formatada,
      ROUND(EXTRACT(EPOCH FROM (NOW() - m.created_at)) / 3600, 1) as horas_uso
    FROM eeg_caixas c
    JOIN eeg_movimentacoes m ON m.caixa_id = c.id 
      AND m.tipo = 'retirada'
      AND m.id = (SELECT MAX(m2.id) FROM eeg_movimentacoes m2 WHERE m2.caixa_id = c.id AND m2.tipo = 'retirada')
    LEFT JOIN eeg_sessao_retirada s ON s.caixa_codigo = c.codigo
      AND s.usuario_id = ${userId}
      AND s.status = 'finalizada'
    LEFT JOIN eeg_exames_continuos ec ON ec.caixa_codigo = c.codigo
      AND ec.tecnico_instalador_id = ${userId}
      AND ec.status IN ('em_andamento', 'aguardando_retirada')
    WHERE c.tecnico_atual_id = ${userId}
      AND c.status = 'em_uso'
    ORDER BY m.created_at DESC
  `;

  respostaJSON = {
    mensagem: "📋 *MEUS EXAMES*\n\nCarregando suas caixas...",
    botoes: [
      { id: "eeg_exames", title: "🔙 Voltar" },
      { id: "modulo_eeg", title: "🔙 Menu EEG" }
    ],
    _preencherMeusExames: true
  };
}

