  const tipo = match[1].toLowerCase();
  const caixa = match[2].toUpperCase();

  if (tipo === 'hospitalar') {
    // Redirecionar para fluxo hospitalar COM caixa na sessão
    executarSQLAntes = true;
    sqlAcaoAntes = 'listar_regioes_hospitais';
