          '{"tipo_sessao": "exame", "tipo_atendimento": "residencial", "caixa_exame": "${caixa}", "aguardando": "paciente_nome"}'::jsonb,
        NOW(), NOW(), NOW() + INTERVAL '30 minutes'
      )
        RETURNING id
      )
      SELECT id, nome FROM eeg_locais_parceiros 
      WHERE tipo = 'clinica' AND ativo = true
      ORDER BY nome
    `;

    respostaJSON = {
      mensagem: "🏢 *Carregando clínicas...*",
      _preencherListaClinicas: true
    };
  } else {
    // Residencial
    executarSQLAntes = true;
    sqlAcaoAntes = 'criar_sessao_residencial';
    sqlQueryAntes = `
      WITH cleanup AS (
        UPDATE eeg_sessao_retirada 
        SET status = 'cancelada', atualizada_em = NOW()
        WHERE telefone LIKE '%' || RIGHT('${telefone}', 11) || '%'
