function handleRelStatusEquipamentos() {
  executarSQLAntes = true;
  sqlAcaoAntes = 'relatorio_status_equipamentos_v16';
  sqlQueryAntes = `
    WITH caixas_em_uso AS (
      SELECT 
        c.tecnico_atual_id as tecnico_id,
        u.nome as tecnico_nome,
        c.codigo as caixa_codigo,
        c.data_ultima_retirada,
        TO_CHAR(c.data_ultima_retirada, 'DD/MM HH24:MI') as retirada_formatada,
        ROUND(EXTRACT(EPOCH FROM (NOW() - c.data_ultima_retirada))/3600, 1) as horas_uso,
        13 as total_itens,
        13 - COALESCE((
          SELECT COUNT(DISTINCT item_numero) 
          FROM eeg_problemas pr 
          WHERE UPPER(pr.caixa_codigo) = UPPER(c.codigo) 
            AND pr.status = 'pendente'
        ), 0) as itens_ok,
        (
          SELECT e.hospital_nome
          FROM eeg_exames e
          WHERE UPPER(e.caixa_codigo) = UPPER(c.codigo)
            AND e.status IN ('em_andamento', 'devolucao_parcial')
          ORDER BY e.id DESC
          LIMIT 1
        ) as hospital
      FROM eeg_caixas c
      JOIN hub_usuarios u ON u.id = c.tecnico_atual_id
      WHERE c.status = 'em_uso' AND c.tecnico_atual_id IS NOT NULL
      ORDER BY u.nome, c.codigo
    ),
    caixas_disponiveis AS (
      SELECT 
        c.codigo,
        COALESCE((
          SELECT COUNT(DISTINCT item_numero) 
          FROM eeg_problemas pr 
          WHERE UPPER(pr.caixa_codigo) = UPPER(c.codigo) 
            AND pr.status = 'pendente'
        ), 0) as itens_problema
      FROM eeg_caixas c
      WHERE c.status = 'disponivel' AND c.bloqueada = false
      ORDER BY c.codigo
    ),
    resumo AS (
      SELECT 
        (SELECT COUNT(*) FROM eeg_caixas WHERE status = 'em_uso') as em_uso,
        (SELECT COUNT(*) FROM eeg_caixas WHERE status = 'disponivel') as disponiveis,
        (SELECT COUNT(DISTINCT caixa_codigo) FROM eeg_problemas WHERE status = 'pendente') as com_problema
    )
    SELECT 
      (SELECT COALESCE(json_agg(row_to_json(t)), '[]') FROM caixas_em_uso t) as tecnicos,
      (SELECT COALESCE(json_agg(row_to_json(d)), '[]') FROM caixas_disponiveis d) as disponiveis,
      (SELECT row_to_json(r) FROM resumo r) as resumo
  `;

  respostaJSON = {
    mensagem: "⏳ Carregando status...",
    botoes: [{ id: "eeg_relatorios", title: "🔙 Relatórios" }],
    _preencherStatusEquipamentosV16: true
  };
}

