// VERIFICAR DUPLICATA - CORRIGIDO V2
// ============================================

const entrada = $input.first().json;

let telefone = '';
let content = '';
let buttonId = null;
let tipoInteracao = 'texto';
let messageId = '';
let imageUrl = null;

// ============================================
// DETECTAR ESTRUTURA DO WEBHOOK
// ============================================

// Estrutura 1: Webhook já processado (seu caso atual)
if (entrada.message && entrada.message.contactPhone) {
  const msg = entrada.message;

  telefone = msg.contactPhone || msg.senderPhone || '';
  content = msg.content || msg.body || '';
  buttonId = msg.buttonId || null;
  messageId = msg.messageId || '';
  tipoInteracao = msg.messageType || 'text';

  // Detectar se é interativo
  if (msg.buttonId) {
    tipoInteracao = 'botao';
  }
}
// Estrutura 2: Webhook raw do 360Dialog
else if (entrada.messages && entrada.messages[0]) {
  const mensagem = entrada.messages[0];
  messageId = mensagem.id || '';
  telefone = mensagem.from || entrada.contacts?.[0]?.wa_id || '';

  const tipoMensagem = mensagem.type || 'text';

  if (tipoMensagem === 'text') {
    content = mensagem.text?.body || '';
    tipoInteracao = 'texto';
  }
  else if (tipoMensagem === 'interactive') {
    const interactive = mensagem.interactive || {};
    const tipoInterativo = interactive.type || '';

    if (tipoInterativo === 'button_reply') {
      buttonId = interactive.button_reply?.id || null;
      content = interactive.button_reply?.title || '';
      tipoInteracao = 'botao';
    }
    else if (tipoInterativo === 'list_reply') {
      buttonId = interactive.list_reply?.id || null;
      content = interactive.list_reply?.title || '';
      tipoInteracao = 'lista';
    }
  }
  else if (tipoMensagem === 'image') {
    content = mensagem.image?.caption || '[Imagem]';
    tipoInteracao = 'imagem';
    imageUrl = mensagem.image?.id || null;
  }
}
// Estrutura 3: Dados diretos
else {
  telefone = entrada.phone || entrada.from || entrada.telefone || entrada.contactPhone || entrada.senderPhone || '';
  content = entrada.body || entrada.text || entrada.content || entrada.message || '';
  buttonId = entrada.buttonId || entrada.selectedButtonId || null;
  messageId = entrada.id || entrada.messageId || '';
}

// Limpar telefone (remover caracteres não numéricos)
if (telefone) {
  telefone = telefone.toString().replace(/\D/g, '');
}

// Garantir que temos um telefone válido
if (!telefone && entrada.message) {
  telefone = (entrada.message.contactPhone || entrada.message.senderPhone || '').replace(/\D/g, '');
}

// Gerar ID único para deduplicação
const uniqueId = messageId || `${telefone}_${Date.now()}`;

return [{
  json: {
    telefone: telefone,
    content: content,
    buttonId: buttonId,
    tipoInteracao: tipoInteracao,
    messageId: messageId,
    uniqueId: uniqueId,
    message: entrada.message || entrada,
    imageUrl: imageUrl
  }
}];

