	function buildItemLineFromJson(item) {
	  const n = item.numero;
	  const nome = item.nome || getNomesItens()[n] || 'Item ' + n;
	  const status = item.status || 'disponivel';
	  let linha = '';

	  switch(status) {
		case 'defeito':
		  linha = `🔴 ${n}. ${nome} (defeito${item.problema_descricao ? ' - ' + item.problema_descricao : ''})`;
		  break;
		case 'faltando':
		  linha = `🟡 ${n}. ${nome} (faltando)`;
		  break;
		case 'manutencao':
		  linha = `🔧 ${n}. ${nome} (manutenção)`;
		  break;
		case 'emprestado':
		  linha = `🔄 ${n}. ${nome} (emprestado${item.emprestado_para ? ' p/ ' + item.emprestado_para : ''})`;
		  break;
		case 'com_paciente':
		  linha = `🏥 ${n}. ${nome} (com paciente)`;
		  break;
		default:
		  return `✅ ${n}. ${nome}`;
	  }

	  // Linha extra para itens com problema: quem reportou + última nota
	  if (['defeito', 'faltando', 'manutencao'].includes(status)) {
		let extra = '';
		if (item.reportado_por_nome) {
		  extra += `👤 ${item.reportado_por_nome}`;
		  if (item.reportado_em) {
			// Pegar só DD/MM do formato DD/MM/YYYY HH24:MI
			const dataCurta = item.reportado_em.substring(0, 5);
			extra += ` (${dataCurta})`;
		  }
		}
		if (item.ultima_nota) {
		  if (extra) extra += ' · ';
		  extra += `📋 ${item.ultima_nota}`;
		}
		if (extra) {
		  linha += `\n   ${extra}`;
		}
	  }

	  return linha;
	}

	// ============================================
	// FUNÇÃO AUXILIAR: Adicionar separadores visuais em itens com problema
	// ============================================
	function formatarListaComSeparadores(texto) {
	  if (!texto) return texto;
	  const linhas = texto.split('\n');
	  const resultado = [];
	  let dentroBloco = false;
	  const SEP = '───────────────────────────';

	  for (let i = 0; i < linhas.length; i++) {
		let linha = linhas[i].replace(/👤/g, '👨‍⚕️');
		const trimmed = linha.trim();

		if (!trimmed) { resultado.push(linha); continue; }

		const ehNormal = trimmed.startsWith('✅');
		const ehDetalhe = /^\s/.test(linhas[i]) && !trimmed.startsWith('✅');

		if (!ehNormal && !ehDetalhe) {
		  // Início de item com problema
		  if (!dentroBloco) {
			resultado.push(SEP);
			dentroBloco = true;
		  }
		} else if (ehNormal && dentroBloco) {
		  // Voltou a item normal → fechar bloco
		  resultado.push(SEP);
		  dentroBloco = false;
		}

		resultado.push(linha);
	  }

	  if (dentroBloco) resultado.push(SEP);

	  return resultado.join('\n');
	}

