		  const itemNum = parseInt(e.item_numero) || 0;
		  const itemNome = e.item_nome || NOMES_ITENS[itemNum] || `Item ${itemNum}`;

		  // Calcular tempo desde empréstimo
		  let tempoTexto = '';
		  if (e.emprestado_em) {
			const emprestadoEm = new Date(e.emprestado_em);
			const agora = new Date();
			const diffMs = agora - emprestadoEm;
			const diffHoras = Math.floor(diffMs / (1000 * 60 * 60));
			const diffDias = Math.floor(diffHoras / 24);

			if (diffDias > 0) {
			  tempoTexto = `${diffDias} dia(s) ${diffHoras % 24}h`;
			} else {
			  tempoTexto = `${diffHoras}h ${Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60))}min`;
